from typing import List

def expectation_number(scores: List[int]) -> int:
    n = len(scores)
    scores.sort()
    return sum([k * (1 / n) for k in range(n)])

def arrange_ark_pairs(ark_deck: List[int]) -> int:
    n = len(ark_deck)
    if n % 2 == 0:
        return 1
    else:
        for i in range(n):
            if ark_deck[i] != 0:
                return i + 1
    return 0

